Implementing a feature that tracks users' location in real-time and displays it on a map using GPS data involves several steps:

**Step 1: Choose a Mapping Library**

1. **Google Maps**: Use the Google Maps API to display maps and track users' location.
2. **OpenStreetMap**: Use the OpenStreetMap API to display maps and track users' location.
3. **Mapbox**: Use the Mapbox API to display maps and track users' location.

**Step 2: Request Location Permissions**

1. **Android**: Request location permissions using the `requestLocationUpdates()` method.
2. **iOS**: Request location permissions using the `requestWhenInUseAuthorization()` method.

**Step 3: Get GPS Data**

1. **Android**: Use the `LocationManager` class to get GPS data.
2. **iOS**: Use the `CLLocationManager` class to get GPS data.

**Step 4: Update Map with GPS Data**

1. **Android**: Use the `GoogleMap` class to update the map with GPS data.
2. **iOS**: Use the `MKMapView` class to update the map with GPS data.

**Step 5: Display GPS Data on Map**

1. **Android**: Use the `Marker` class to display GPS data on the map.
2. **iOS**: Use the `MKAnnotation` class to display GPS data on the map.

**Step 6: Handle GPS Data Updates**

1. **Android**: Use the `LocationListener` interface to handle GPS data updates.
2. **iOS**: Use the `CLLocationManagerDelegate` protocol to handle GPS data updates.

**Example Code (Android)**

```java
import android.location.Location;
import android.location.LocationManager;
import android.os.Bundle;
import android.support.v7.app.AppCompatActivity;
import android.util.Log;

import com.google.android.gms.maps.CameraUpdateFactory;
import com.google.android.gms.maps.GoogleMap;
import com.google.android.gms.maps.OnMapReadyCallback;
import com.google.android.gms.maps.SupportMapFragment;
import com.google.android.gms.maps.model.LatLng;
import com.google.android.gms.maps.model.MarkerOptions;

public class MainActivity extends AppCompatActivity implements OnMapReadyCallback {

    private GoogleMap mMap;
    private LocationManager locationManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        SupportMapFragment mapFragment = (SupportMapFragment) getSupportFragmentManager()
                .findFragmentById(R.id.map);
        mapFragment.getMapAsync(this);

        locationManager = (LocationManager) getSystemService(LOCATION_SERVICE);
    }

    @Override
    public void onMapReady(GoogleMap googleMap) {
        mMap = googleMap;

        locationManager.requestLocationUpdates(LocationManager.GPS_PROVIDER, 0, 0, new LocationListener() {
            @Override
            public void onLocationChanged(Location location) {
                LatLng latLng = new LatLng(location.getLatitude(), location.getLongitude());
                mMap.moveCamera(CameraUpdateFactory.newLatLng(latLng));
                mMap.animateCamera(CameraUpdateFactory.zoomTo(15));
            }

            @Override
            public void onStatusChanged(String provider, int status, Bundle extras) {

            }

            @Override
            public void onProviderEnabled(String provider) {

            }

            @Override
            public void onProviderDisabled(String provider) {

            }
        });
    }
}
```

**Example Code (iOS)**

```swift
import UIKit
import MapKit

class ViewController: UIViewController, MKMapViewDelegate {

    @IBOutlet weak var mapView: MKMapView!

    override func viewDidLoad() {
        super.viewDidLoad()

        let locationManager = CLLocationManager()
        locationManager.requestWhenInUseAuthorization()
        locationManager.startUpdatingLocation()

        mapView.delegate = self
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        let location = locations.last
        let latLng = CLLocationCoordinate2D(latitude: location!.coordinate.latitude, longitude: location!.coordinate.longitude)
        let annotation = MKPointAnnotation()
        annotation.coordinate = latLng
        mapView.addAnnotation(annotation)
        mapView.setCenter(latLng, animated: true)
    }
}
```

Note: This is a basic example and you may need to modify it to fit your specific requirements. Additionally, you will need to add the necessary permissions and API keys to your project.
